<script setup lang="ts">
import type { DatePickerInstance } from "@vuepic/vue-datepicker";
import VueDatePicker from "@vuepic/vue-datepicker";
import "@vuepic/vue-datepicker/dist/main.css";
import {
addDays,
format,
isSameDay,
setHours,
setMinutes,
setSeconds,
subDays,
} from "date-fns";

import ChevronLeft from "~/components/icons/ChevronLeft/index.vue";
import ChevronRight from "~/components/icons/ChevronRight/index.vue";
import Button from "../Button/index.vue";
import IconButton from "../IconButton/index.vue";
import OutlinedButton from "../OutlinedButton/index.vue";

const props = defineProps({
  modelValue: {
    type: Date,
    default: new Date(),
  },
  minDate: {
    type: [Date, Object as () => null],
    default: subDays(new Date(), 1),
  },
  maxDate: {
    type: [Date, Object as () => null],
    default: new Date(),
  },
  isLoading: {
    type: Boolean,
    default: false,
  },
  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
});

const datePicker = ref<DatePickerInstance | null>(null);

const emit = defineEmits(["update:model-value"]);

const formatDate = (date: Date) => {
  const formattedDate = format(date, "dd MMMM yyyy");
  const isToday = isSameDay(date, new Date());

  return `${isToday ? "Today, " : ""}${formattedDate}`;
};

const pickerClass = computed(() => `custom-date-picker date-picker-${props.color}`);

</script>

<template>
  <div class="flex items-center">
    <IconButton
      :disabled="isSameDay(props.modelValue, props.minDate) || props.isLoading"
      class="!h-10 bg-white rounded-r-none border-r-transparent"
      @on-click="emit('update:model-value', subDays(props.modelValue, 1))"
    >
      <template #icon>
        <ChevronLeft size="20" />
      </template>
    </IconButton>

    <vue-date-picker
      ref="datePicker"
      input-class-name="!h-10 !py-2 !rounded-none focus:!ring-success-500"
      calendar-cell-class-name="!rounded-full"
      :model-value="props.modelValue"
      :clearable="false"
      :min-date="props.minDate"
      :max-date="props.maxDate"
      :enable-time-picker="false"
      :format="formatDate"
      :class="pickerClass"
    
      @update:model-value="
        emit(
          'update:model-value',
          setHours(setMinutes(setSeconds($event, 0), 0), 0)
        )
      "
    >
      <template #action-row="{ modelValue, selectDate }">
        <div class="!w-full flex space-x-3">
          <OutlinedButton
            label="Cancel"
            class="w-full"
            :color="color"
            @on-click="datePicker?.closeMenu()"
          />
          <Button
            :color="color"
            label="Confirm"
            class="w-full"
            @on-click="selectDate"
          />
        </div>
      </template>
    </vue-date-picker>

    <IconButton
      :disabled="isSameDay(props.modelValue, props.maxDate) || props.isLoading"
      class="!h-10 bg-white rounded-l-none border-l-transparent"
      @on-click="emit('update:model-value', addDays(props.modelValue, 1))"
    >
      <template #icon>
        <ChevronRight size="20" />
      </template>
    </IconButton>
  </div>
</template>

